import './App.css';
import UserAuth from './components/UserAuth';
import Home from './components/Home';
import Journal from './components/Journal';
import Tasks from './components/Tasks';
import Dashboard from './components/Dashboard';
import History from './components/History';
import { BrowserRouter, Routes, Route, useNavigate, useParams, Router } from 'react-router-dom';
import Signin from './components/Signin';
import Login from './components/Login';
import { AuthProvider } from './components/AuthContext';
import { useAuth } from './components/AuthContext';
function App() {
  return (
    <div className="App">
      <AuthProvider>
        <Routes>
          <Route path="/history" element={<HistoryWrapper />} />
          <Route path="/journal/:id?" element={<JournalWrapper />} />
          <Route path='/home' element={<Home />}></Route>
          <Route path='/' element={<Signin />}></Route>
          <Route path='/login' element={<Login />}></Route>
          <Route path='/journal' element={<Journal />}></Route>
          <Route path='/tasks' element={<Tasks />}></Route>
          <Route path='/dashboard' element={<Dashboard />}></Route>
          <Route path='/history' element={<History />}></Route>
        </Routes>
      </AuthProvider>
    </div >
  );
}
function HistoryWrapper() {
  const navigate = useNavigate();

  const handleEditEntry = (id) => {
    navigate(`/journal/${id}`);
  };

  return <History onEditEntry={handleEditEntry} />;
}

function JournalWrapper() {
  const { id } = useParams();
  const navigate = useNavigate();

  const onSaveComplete = () => {
    navigate('/history');
  };

  return <Journal editEntryId={id ? id : null} onSaveComplete={onSaveComplete} />;
}
export default App;
